public void testModulus2EOF() throws Exception {
    // Create input that results in modulus=2 at EOF (2 base64 chars)
    byte[] input = StringUtils.getBytesUtf8("AA");
    ByteArrayInputStream data = new ByteArrayInputStream(input);
    Base64InputStream stream = new Base64InputStream(data);

    byte[] decodedBytes = Base64TestData.streamToBytes(stream, new byte[1024]);
    assertNotNull("Decoded bytes should not be null", decodedBytes);
    assertTrue("Should decode at least one byte", decodedBytes.length > 0);
}

public void testModulus3EOF() throws Exception {
    // Create input that results in modulus=3 at EOF (3 base64 chars)
    byte[] input = StringUtils.getBytesUtf8("AAA");
    ByteArrayInputStream data = new ByteArrayInputStream(input);
    Base64InputStream stream = new Base64InputStream(data);

    byte[] decodedBytes = Base64TestData.streamToBytes(stream, new byte[1024]);
    assertNotNull("Decoded bytes should not be null", decodedBytes);
    assertTrue("Should decode at least two bytes", decodedBytes.length >= 2);
}

public void testEmptyBufferWithPadding() throws Exception {
    // Test encoding with explicit padding at EOF
    byte[] input = StringUtils.getBytesUtf8("A");
    ByteArrayOutputStream data = new ByteArrayOutputStream();
    Base64OutputStream stream = new Base64OutputStream(data, true);
    stream.write(input);
    stream.close();

    byte[] encodedBytes = data.toByteArray();
    assertNotNull("Encoded bytes should not be null", encodedBytes);
    assertTrue("Should produce encoded output", encodedBytes.length > 0);
}
